BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;
DO $$ BEGIN IF NOT EXISTS(SELECT 1 FROM public.revenue_os_installations WHERE installation_key='revenue-command-os' AND release_code='AC-REVENUE-OS-MZ15-PREMIUM-COCKPIT') THEN RAISE EXCEPTION 'MZ15 prerequisite missing'; END IF; END $$;

CREATE TABLE IF NOT EXISTS public.revenue_os_strategy_outcomes(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,strategy_id uuid NOT NULL,strategy_version_id uuid NOT NULL,objective_id uuid NOT NULL,council_run_id uuid,approval_id uuid,compilation_id uuid,propagation_id uuid,status text NOT NULL DEFAULT 'observing',planned_revenue numeric(18,2) NOT NULL DEFAULT 0,actual_revenue numeric(18,2) NOT NULL DEFAULT 0,planned_margin numeric(9,4) NOT NULL DEFAULT 0,actual_margin numeric(9,4) NOT NULL DEFAULT 0,pipeline_created numeric(18,2) NOT NULL DEFAULT 0,meetings integer NOT NULL DEFAULT 0,proposals integer NOT NULL DEFAULT 0,conversions integer NOT NULL DEFAULT 0,execution_completeness numeric(9,4) NOT NULL DEFAULT 0,attribution_confidence numeric(9,4) NOT NULL DEFAULT 0,lessons jsonb NOT NULL DEFAULT '[]',observed_at timestamptz NOT NULL DEFAULT now(),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,strategy_version_id,compilation_id));
CREATE TABLE IF NOT EXISTS public.revenue_os_command_performance(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,command_code text NOT NULL,segment text NOT NULL DEFAULT '',territory text NOT NULL DEFAULT '',selections bigint NOT NULL DEFAULT 0,executions bigint NOT NULL DEFAULT 0,successes bigint NOT NULL DEFAULT 0,revenue_contribution numeric(18,2) NOT NULL DEFAULT 0,margin_contribution numeric(18,2) NOT NULL DEFAULT 0,success_rate numeric(9,4) NOT NULL DEFAULT 0,confidence numeric(9,4) NOT NULL DEFAULT 0,state text NOT NULL DEFAULT 'unproven',evidence jsonb NOT NULL DEFAULT '[]',last_calculated_at timestamptz NOT NULL DEFAULT now(),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,command_code,segment,territory));
CREATE TABLE IF NOT EXISTS public.revenue_os_segment_response_models(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,segment text NOT NULL,territory text NOT NULL DEFAULT '',sample_size integer NOT NULL DEFAULT 0,confidence numeric(9,4) NOT NULL DEFAULT 0,winning_offers jsonb NOT NULL DEFAULT '[]',winning_channels jsonb NOT NULL DEFAULT '[]',winning_messages jsonb NOT NULL DEFAULT '[]',failed_patterns jsonb NOT NULL DEFAULT '[]',response_window text,evidence_ids jsonb NOT NULL DEFAULT '[]',model_version integer NOT NULL DEFAULT 1,recalculated_at timestamptz NOT NULL DEFAULT now(),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,segment,territory,model_version));
CREATE TABLE IF NOT EXISTS public.revenue_os_experiments(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,code text NOT NULL,name text NOT NULL,experiment_type text NOT NULL,hypothesis text NOT NULL,primary_metric text NOT NULL,secondary_metrics jsonb NOT NULL DEFAULT '[]',status text NOT NULL DEFAULT 'draft',eligible_population jsonb NOT NULL DEFAULT '{}',sample_size integer NOT NULL, start_at timestamptz,end_at timestamptz,stop_rules jsonb NOT NULL DEFAULT '[]',risk_limit jsonb NOT NULL DEFAULT '{}',approval_class text NOT NULL DEFAULT 'controlled_experiment',attribution_window_days integer NOT NULL DEFAULT 30,idempotency_key text NOT NULL,created_by uuid,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,code),UNIQUE(tenant_id,idempotency_key));
CREATE TABLE IF NOT EXISTS public.revenue_os_experiment_variants(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,experiment_id uuid NOT NULL REFERENCES public.revenue_os_experiments(id) ON DELETE CASCADE,code text NOT NULL,label text NOT NULL,allocation_percent numeric(9,4) NOT NULL,payload jsonb NOT NULL DEFAULT '{}',is_control boolean NOT NULL DEFAULT false,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(experiment_id,code));
