CREATE INDEX IF NOT EXISTS revenue_os_durable_jobs_claim_idx ON public.revenue_os_durable_jobs(queue_name,status,priority,scheduled_at) WHERE status IN ('queued','retry_scheduled');
CREATE INDEX IF NOT EXISTS revenue_os_durable_jobs_lease_idx ON public.revenue_os_durable_jobs(lease_expires_at) WHERE status='leased';
CREATE INDEX IF NOT EXISTS revenue_os_anomalies_open_idx ON public.revenue_os_anomalies(tenant_id,severity,detected_at DESC) WHERE status='open';
CREATE INDEX IF NOT EXISTS revenue_os_experiments_status_idx ON public.revenue_os_experiments(tenant_id,status,start_at);
CREATE INDEX IF NOT EXISTS revenue_os_strategy_outcomes_strategy_idx ON public.revenue_os_strategy_outcomes(tenant_id,strategy_id,observed_at DESC);
CREATE OR REPLACE FUNCTION public.revenue_os_claim_durable_jobs(p_tenant_id uuid,p_queue text,p_worker text,p_limit integer,p_lease_seconds integer)
RETURNS SETOF public.revenue_os_durable_jobs LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
BEGIN
 RETURN QUERY
 WITH candidates AS (
  SELECT id FROM public.revenue_os_durable_jobs WHERE tenant_id=p_tenant_id AND queue_name=p_queue AND status IN ('queued','retry_scheduled') AND scheduled_at<=now() AND (lease_expires_at IS NULL OR lease_expires_at<=now()) AND attempts<max_attempts ORDER BY priority ASC,scheduled_at ASC FOR UPDATE SKIP LOCKED LIMIT greatest(1,least(p_limit,100))
 ), updated AS (
  UPDATE public.revenue_os_durable_jobs j SET status='leased',lease_owner=p_worker,lease_expires_at=now()+make_interval(secs=>p_lease_seconds),fencing_token=fencing_token+1,attempts=attempts+1,updated_at=now() FROM candidates c WHERE j.id=c.id RETURNING j.*
 ) SELECT * FROM updated;
END $$;
REVOKE ALL ON FUNCTION public.revenue_os_claim_durable_jobs(uuid,text,text,integer,integer) FROM public,anon,authenticated;
GRANT EXECUTE ON FUNCTION public.revenue_os_claim_durable_jobs(uuid,text,text,integer,integer) TO service_role;
DO $$ DECLARE t text; BEGIN FOREACH t IN ARRAY ARRAY['revenue_os_strategy_outcomes','revenue_os_command_performance','revenue_os_segment_response_models','revenue_os_experiments','revenue_os_experiment_variants','revenue_os_experiment_assignments','revenue_os_experiment_outcomes','revenue_os_control_groups','revenue_os_attribution_events','revenue_os_attribution_results','revenue_os_adaptive_schedules','revenue_os_strategy_suppressions','revenue_os_winning_play_scaling','revenue_os_forecast_calibrations','revenue_os_anomalies','revenue_os_outcome_feedback','revenue_os_durable_jobs','revenue_os_worker_registry','revenue_os_worker_leases','revenue_os_distributed_locks','revenue_os_dead_letters','revenue_os_execution_traces','revenue_os_observability_metrics','revenue_os_queue_health_snapshots','revenue_os_registry_entries','revenue_os_evaluation_runs','revenue_os_regression_runs','revenue_os_cost_budgets','revenue_os_cost_usage','revenue_os_confidence_policies','revenue_os_fallback_policies','revenue_os_emergency_stops','revenue_os_disaster_recovery_runs','revenue_os_security_reviews','revenue_os_production_activations','revenue_os_activation_approvals','revenue_os_recovery_runbooks','revenue_os_mega_production_audit_events'] LOOP EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY',t);EXECUTE format('REVOKE ALL ON TABLE public.%I FROM anon, authenticated',t);EXECUTE format('GRANT ALL ON TABLE public.%I TO service_role',t);END LOOP;END $$;
